import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TranscriptionResult {
  rawText: string;
  structuredReport: StructuredReport;
}

export interface StructuredReport {
  patientInfo?: string;
  clinicalHistory?: string;
  findings?: string;
  diagnosis?: string;
  plan?: string;
  originalText: string;
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  TRANSCRIBING = 'TRANSCRIBING',
  REFINING = 'REFINING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { StructuredReport } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Transcribes audio data using gemini-3-flash-preview
 */
export async function transcribeAudio(base64Audio: string, mimeType: string): Promise<string> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: mimeType,
            data: base64Audio,
          },
        },
        {
          text: "Transcribe this medical voice report verbatim. Include all technical medical terms accurately. Do not add any formatting yet, just provide the full raw text.",
        },
      ],
    },
  });

  return response.text || "";
}

/**
 * Refines raw transcription into a structured medical report using gemini-3-pro-preview with Thinking Mode
 */
export async function refineMedicalReport(rawText: string): Promise<StructuredReport> {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `
      Convert the following raw medical transcription into a structured medical report.
      Use professional medical terminology. 
      Identify and separate information into these categories: 
      - Patient Identification (if mentioned)
      - Clinical History
      - Physical Examination/Findings
      - Diagnostic Impression
      - Treatment Plan/Recommendations

      Raw Transcription:
      ${rawText}
    `,
    config: {
      thinkingConfig: { thinkingBudget: 32768 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          patientInfo: { type: Type.STRING, description: "Patient name, age, etc." },
          clinicalHistory: { type: Type.STRING, description: "Symptoms and background." },
          findings: { type: Type.STRING, description: "Physical exam or test results." },
          diagnosis: { type: Type.STRING, description: "Assessment or diagnosis." },
          plan: { type: Type.STRING, description: "Treatment and follow-up." },
        },
        required: ["findings", "diagnosis", "plan"],
      }
    },
  });

  try {
    const data = JSON.parse(response.text || "{}");
    return {
      ...data,
      originalText: rawText
    };
  } catch (e) {
    console.error("Failed to parse AI response as JSON", e);
    return {
      findings: "Error processing report structure.",
      diagnosis: "Could not structure data.",
      plan: "Please review raw text.",
      originalText: rawText
    };
  }
}

import React, { useState, useRef, useCallback } from 'react';
import { AppStatus, StructuredReport } from './types';
import { transcribeAudio, refineMedicalReport } from './services/geminiService';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [report, setReport] = useState<StructuredReport | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    processAudioFile(file);
  };

  const processAudioFile = async (file: File) => {
    try {
      setStatus(AppStatus.UPLOADING);
      setError(null);
      setAudioUrl(URL.createObjectURL(file));

      // Convert file to base64
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => {
          const base64 = (reader.result as string).split(',')[1];
          resolve(base64);
        };
      });
      reader.readAsDataURL(file);
      const base64Audio = await base64Promise;

      // 1. Transcription (Flash)
      setStatus(AppStatus.TRANSCRIBING);
      const rawText = await transcribeAudio(base64Audio, file.type);

      // 2. Refinement (Pro + Thinking)
      setStatus(AppStatus.REFINING);
      const structuredData = await refineMedicalReport(rawText);

      setReport(structuredData);
      setStatus(AppStatus.COMPLETED);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred during processing.');
      setStatus(AppStatus.ERROR);
    }
  };

  const downloadDoc = () => {
    if (!report) return;

    const content = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>Medical Report</title></head>
      <body>
        <h1 style="text-align:center; color:#0f172a;">Medical Report</h1>
        <hr/>
        ${report.patientInfo ? `<h3>Patient Information</h3><p>${report.patientInfo}</p>` : ''}
        ${report.clinicalHistory ? `<h3>Clinical History</h3><p>${report.clinicalHistory}</p>` : ''}
        <h3>Findings</h3><p>${report.findings}</p>
        <h3>Diagnosis</h3><p>${report.diagnosis}</p>
        <h3>Plan</h3><p>${report.plan}</p>
        <br/>
        <hr/>
        <p style="font-size:10px; color:#64748b;">Generated by MedScribe AI on ${new Date().toLocaleDateString()}</p>
      </body>
      </html>
    `;

    const blob = new Blob(['\ufeff', content], {
      type: 'application/msword'
    });

    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Medical_Report_${new Date().getTime()}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setReport(null);
    setAudioUrl(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center py-12 px-4">
      <header className="max-w-4xl w-full mb-12 text-center">
        <div className="flex items-center justify-center space-x-3 mb-4">
          <div className="bg-blue-600 p-3 rounded-2xl shadow-lg shadow-blue-200">
            <i className="fa-solid fa-notes-medical text-white text-3xl"></i>
          </div>
          <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight">MedScribe <span className="text-blue-600">AI</span></h1>
        </div>
        <p className="text-slate-500 text-lg">Intelligent Medical Transcription & Report Structuring</p>
      </header>

      <main className="max-w-4xl w-full">
        {status === AppStatus.IDLE && (
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="group cursor-pointer bg-white border-2 border-dashed border-slate-300 rounded-3xl p-16 text-center transition-all hover:border-blue-500 hover:bg-blue-50/50"
          >
            <input 
              type="file" 
              accept="audio/*" 
              className="hidden" 
              ref={fileInputRef} 
              onChange={handleFileChange}
            />
            <div className="bg-slate-100 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 group-hover:bg-blue-100 transition-colors">
              <i className="fa-solid fa-cloud-arrow-up text-slate-400 text-3xl group-hover:text-blue-600"></i>
            </div>
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Upload Voice Report</h2>
            <p className="text-slate-500 max-w-sm mx-auto">
              Drag and drop your audio file or click to browse. Supports WAV, MP3, M4A, etc.
            </p>
          </div>
        )}

        {(status === AppStatus.UPLOADING || status === AppStatus.TRANSCRIBING || status === AppStatus.REFINING) && (
          <div className="bg-white rounded-3xl p-12 shadow-xl shadow-slate-200 text-center border border-slate-100">
            <div className="relative w-24 h-24 mx-auto mb-8">
              <div className="absolute inset-0 border-4 border-slate-100 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
            </div>
            <h3 className="text-2xl font-bold text-slate-900 mb-4">
              {status === AppStatus.UPLOADING && 'Uploading Medical Data...'}
              {status === AppStatus.TRANSCRIBING && 'Transcribing Voice Record...'}
              {status === AppStatus.REFINING && 'Analyzing & Structuring Report...'}
            </h3>
            <p className="text-slate-500 italic max-w-md mx-auto">
              {status === AppStatus.TRANSCRIBING && 'Gemini Flash is converting your voice report to text with clinical precision.'}
              {status === AppStatus.REFINING && 'Gemini Pro is applying reasoning to structure your report into professional sections.'}
            </p>
          </div>
        )}

        {status === AppStatus.ERROR && (
          <div className="bg-red-50 border border-red-100 rounded-3xl p-8 text-center">
            <i className="fa-solid fa-circle-exclamation text-red-500 text-4xl mb-4"></i>
            <h3 className="text-xl font-bold text-red-900 mb-2">Processing Error</h3>
            <p className="text-red-700 mb-6">{error}</p>
            <button 
              onClick={reset}
              className="bg-white border border-red-200 text-red-600 px-6 py-2 rounded-xl font-medium hover:bg-red-100 transition-colors"
            >
              Try Again
            </button>
          </div>
        )}

        {status === AppStatus.COMPLETED && report && (
          <div className="space-y-6">
            <div className="bg-white rounded-3xl p-8 shadow-xl shadow-slate-200 border border-slate-100">
              <div className="flex items-center justify-between mb-8 pb-4 border-b border-slate-100">
                <h2 className="text-2xl font-bold text-slate-900 flex items-center">
                  <i className="fa-solid fa-file-medical text-blue-600 mr-3"></i>
                  Clinical Report Result
                </h2>
                <div className="flex space-x-2">
                  <button 
                    onClick={downloadDoc}
                    className="flex items-center space-x-2 bg-blue-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-200"
                  >
                    <i className="fa-solid fa-file-word"></i>
                    <span>Download .doc</span>
                  </button>
                  <button 
                    onClick={reset}
                    className="flex items-center space-x-2 bg-slate-100 text-slate-600 px-5 py-2.5 rounded-xl font-bold hover:bg-slate-200 transition-all"
                  >
                    <i className="fa-solid fa-rotate-left"></i>
                    <span>New Transcription</span>
                  </button>
                </div>
              </div>

              {audioUrl && (
                <div className="mb-8 p-4 bg-slate-50 rounded-2xl flex items-center space-x-4">
                  <i className="fa-solid fa-circle-play text-blue-500 text-xl"></i>
                  <audio src={audioUrl} controls className="w-full h-10 accent-blue-600" />
                </div>
              )}

              <div className="grid grid-cols-1 gap-8">
                {report.patientInfo && (
                  <Section title="Patient Information" content={report.patientInfo} icon="fa-user-md" />
                )}
                <Section title="Clinical History" content={report.clinicalHistory} icon="fa-clock-rotate-left" />
                <Section title="Findings & Observations" content={report.findings} icon="fa-stethoscope" highlight />
                <Section title="Diagnosis / Assessment" content={report.diagnosis} icon="fa-microscope" />
                <Section title="Plan & Recommendations" content={report.plan} icon="fa-clipboard-check" />

                <div className="mt-8 pt-6 border-t border-slate-100">
                  <details className="group">
                    <summary className="cursor-pointer text-slate-400 font-medium flex items-center hover:text-slate-600 transition-colors">
                      <i className="fa-solid fa-chevron-right mr-2 transition-transform group-open:rotate-90"></i>
                      View Raw Transcription
                    </summary>
                    <div className="mt-4 p-4 bg-slate-50 rounded-xl text-slate-600 text-sm leading-relaxed whitespace-pre-wrap">
                      {report.originalText}
                    </div>
                  </details>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="mt-auto pt-12 pb-6 text-slate-400 text-sm">
        <p>© 2024 MedScribe AI. Secure Clinical Documentation Interface.</p>
      </footer>
    </div>
  );
};

interface SectionProps {
  title: string;
  content?: string;
  icon: string;
  highlight?: boolean;
}

const Section: React.FC<SectionProps> = ({ title, content, icon, highlight }) => {
  if (!content) return null;
  return (
    <div className={`p-6 rounded-2xl border ${highlight ? 'bg-blue-50/30 border-blue-100' : 'bg-white border-slate-100'}`}>
      <h3 className="flex items-center text-lg font-bold text-slate-800 mb-3">
        <i className={`fa-solid ${icon} text-blue-500 mr-2 opacity-70`}></i>
        {title}
      </h3>
      <div className="text-slate-600 leading-relaxed whitespace-pre-wrap">
        {content}
      </div>
    </div>
  );
};

export default App;

